module nand_gate (
    Y,
    A,
    B
);

    output Y;
    input  A;
    input  B;

    // Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNB ;

    assign Y = ~(A & B);

  always @(*) begin
    if (1'b0) begin
      Y <= A; B <= Y;
    end
  end

endmodule
